  function localizeFooterBlocks() {
    const footer = first('footer .footer-grid');
    if (!footer) return;
    const cols = all(':scope > div', footer);
    cols.forEach(col => {
      const heading = first('h4', col);
      const links = all('a', col);
      const hrefs = links.map(a => (a.getAttribute('href') || '').toLowerCase());
      if (!links.length) {
        if (heading) heading.textContent = tx('brand');
        const p = first('p', col);
        if (p) p.textContent = location.pathname.toLowerCase().includes('/tools/') ? localize(COMMON_PAGE_STRINGS.footer_tagline_tools) : localize(COMMON_PAGE_STRINGS.footer_tagline_home);
        return;
      }
      const hasInfo = hrefs.some(h => /about\.html|privacy\.html|contact\.html/.test(h));
      const hasQuick = hrefs.some(h => /index\.html|^\.\/$|roadmap\.html|changelog\.html/.test(h));
      const hasLinkOnly = hrefs.some(h => /tools\//.test(h)) && !hasInfo && !hasQuick;
      if (heading) {
        if (hasInfo) heading.textContent = tx('footer_info');
        else if (hasQuick) heading.textContent = tx('footer_quick');
        else if (hasLinkOnly) heading.textContent = tx('footer_links');
      }
      links.forEach(a => {
        const href = (a.getAttribute('href') || '').toLowerCase();
        if (/#featured$/.test(href)) a.textContent = tx('nav_featured');
        else if (/\/tools\/?$/.test(href) || href === './') a.textContent = tx('nav_tools');
        else if (/changelog\.html/.test(href)) a.textContent = tx('changelog_h1');
        else if (/roadmap\.html/.test(href)) a.textContent = tx('roadmap_h1');
        else if (/privacy\.html/.test(href)) a.textContent = tx('privacy_h1');
        else if (/contact\.html/.test(href)) a.textContent = tx('nav_contact');
        else if (/about\.html/.test(href)) a.textContent = tx('nav_about');
        else if (/index\.html$/.test(href)) a.textContent = tx('nav_home');
      });
    });
  }

